    font-weight: 600;
    cursor: pointer;
    font-size: 0.9rem;
    transition: background-color 0.15s;
    white-space: nowrap;
}

.send-btn:hover:not(:disabled) {
    background-color: #357abd;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

