arguments.file_text:
@using sv_3592b303bfd84567ab4aedaa2bfe942c.Services

<div class="message-item" @onmouseenter="ShowActions" @onmouseleave="HideActions">
    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp">@TimeHelper.FormatRelative(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge"
                        @onclick="() => OnReact.InvokeAsync((Message.Id, reaction.Emoji))">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (showActions)
    {
        <div class="message-actions">
            <button @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply in thread">
                💬 Reply
            </button>
            <button @onclick="ToggleEmojiPicker" title="Add reaction">
                😀 React
            </button>
        </div>

        @if (showEmojiPicker)
        {
            <div class="emoji-picker-anchor">
                <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
            </div>
        }
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool showActions;
    private bool showEmojiPicker;

    private void ShowActions() => showActions = true;

    private void HideActions()
    {
        showActions = false;
        showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task HandleEmojiSelected(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }
}

.message-item {
    padding: 8px 16px;
    position: relative;
    transition: background-color 0.1s;
}

.message-item:hover {
    background-color: #f8f8f8;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 0.95rem;
    color: #1a1a1a;
}

.timestamp {
    font-size: 0.75rem;
    color: #999;
}

.message-content {
    font-size: 0.93rem;
    color: #333;
    line-height: 1.45;
    word-break: break-word;
}

.reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: #f0f4f8;
    border: 1px solid #d0dbe8;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background-color 0.1s;
}

.reaction-badge:hover {
    background: #dce6f0;
}

.thread-link {
    background: none;
    border: none;
    color: #4a90d9;
    font-size: 0.82rem;
    font-weight: 600;
    cursor: pointer;
    padding: 2px 0;
    margin-top: 4px;
    display: block;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: 4px;
    right: 16px;
    display: flex;
    gap: 4px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
    z-index: 10;
}

.message-actions button {
    background: none;
    border: none;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    font-size: 0.8rem;
    white-space: nowrap;
    transition: background-color 0.1s;
}

.message-actions button:hover {
    background-color: #f0f0f0;
}

.emoji-picker-anchor {
    position: absolute;
    top: 4px;
    right: 16px;
    z-index: 20;
}

@using sv_3592b303bfd84567ab4aedaa2bfe942c.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == SelectedChannelId"
                         OnClick="() => OnChannelSelected.InvokeAsync(channel.Id)" />
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    background-color: #2c2f33;
    color: #e0e0e0;
    display: flex;
    flex-direction: column;
    height: 100%;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #fff;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

