export function init(element, dotNetRef) {
    if (!element) return;
    const handler = () => {
        if (element.scrollTop <= 1) {
            dotNetRef.invokeMethodAsync('OnScrolledToTop');
        }
    };
    element._chatScrollHandler = handler;
    element.addEventListener('scroll', handler);
    // Start scrolled to bottom
    element.scrollTop = element.scrollHeight;
}

export function scrollToBottom(element) {
    if (element) {
        element.scrollTop = element.scrollHeight;
    }
}

export function dispose(element) {
    if (element?._chatScrollHandler) {
        element.removeEventListener('scroll', element._chatScrollHandler);
        delete element._chatScrollHandler;
    }
}

@using sv_3592b303bfd84567ab4aedaa2bfe942c.Services
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="message-list" @ref="scrollContainer">
    @if (IsLoadingMore)
    {
        <div class="loading-indicator">Loading older messages…</div>
    }
    else if (HasMoreMessages)
    {
        <div class="load-more-sentinel"></div>
    }

    @foreach (var message in Messages)
    {
        <MessageItem Message="message"
                     ReplyCount="GetReplyCount(message.Id)"
                     OnOpenThread="OnOpenThread"
                     OnReact="OnReact" />
    }
</div>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ReplyCountMap { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private ElementReference scrollContainer;
    private IJSObjectReference? module;
    private DotNetObjectReference<MessageList>? dotNetRef;
    private bool initialized;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
