export function init(element, dotNetRef) {
    if (!element) return;
    const handler = () => {
        if (element.scrollTop <= 1) {
            dotNetRef.invokeMethodAsync('OnScrolledToTop');
        }
    };
    element._chatScrollHandler = handler;
    element.addEventListener('scroll', handler);
    // Start scrolled to bottom
    element.scrollTop = element.scrollHeight;
}

export function scrollToBottom(element) {
    if (element) {
        element.scrollTop = element.scrollHeight;
    }
}

export function dispose(element) {
    if (element?._chatScrollHandler) {
        element.removeEventListener('scroll', element._chatScrollHandler);
        delete element._chatScrollHandler;
    }
}

