toolArgs.file_text:
@using sv_3592b303bfd84567ab4aedaa2bfe942c.Services

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    <div class="thread-root">
        <div class="message-header">
            <span class="author">@RootMessage.Author</span>
            <span class="timestamp">@TimeHelper.FormatRelative(RootMessage.SentAt)</span>
        </div>
        <div class="message-content">@RootMessage.Content</div>
    </div>

    <div class="thread-divider">
        <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
    </div>

    <div class="thread-replies">
        @foreach (var reply in Replies)
        {
            <div class="thread-reply">
                <div class="message-header">
                    <span class="author">@reply.Author</span>
                    <span class="timestamp">@TimeHelper.FormatRelative(reply.SentAt)</span>
                </div>
                <div class="message-content">@reply.Content</div>
            </div>
        }
    </div>

    <MessageInput Placeholder="Reply in thread…" ButtonLabel="Reply" OnSend="OnSendReply" />
</div>

@code {
    [Parameter, EditorRequired] public Message RootMessage { get; set; } = default!;
    [Parameter, EditorRequired] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
}

.thread-panel {
    background: #fff;
    border-left: 1px solid #e0e0e0;
    display: flex;
    flex-direction: column;
    height: 100%;
    overflow: hidden;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1.05rem;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    cursor: pointer;
    color: #666;
    padding: 4px 8px;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.close-btn:hover {
    background-color: #f0f0f0;
    color: #333;
}

.thread-root {
    padding: 12px 16px;
    background-color: #fafafa;
    border-bottom: 1px solid #e0e0e0;
}

.thread-root .message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.thread-root .author {
    font-weight: 700;
    font-size: 0.93rem;
    color: #1a1a1a;
}

.thread-root .timestamp {
    font-size: 0.75rem;
    color: #999;
}

.thread-root .message-content {
    font-size: 0.9rem;
    color: #333;
    line-height: 1.4;
}

.thread-divider {
    padding: 8px 16px;
    font-size: 0.78rem;
    color: #888;
    border-bottom: 1px solid #eee;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

.thread-reply {
    padding: 8px 16px;
}

.thread-reply .message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.thread-reply .author {
    font-weight: 700;
    font-size: 0.9rem;
    color: #1a1a1a;
}

.thread-reply .timestamp {
    font-size: 0.73rem;
    color: #999;
}

.thread-reply .message-content {
    font-size: 0.9rem;
    color: #333;
    line-height: 1.4;
}

