arguments.file_text:
@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@using sv_3592b303bfd84567ab4aedaa2bfe942c.Services
@inject IChatService ChatService

<div class="chat-container @(isThreadOpen ? "thread-open" : "")">
    <ChannelSidebar Channels="channels"
                    SelectedChannelId="selectedChannelId"
                    OnChannelSelected="HandleChannelSelected" />

    <div class="main-area">
        @if (selectedChannel is not null)
        {
            <div class="channel-header">
                <h2># @selectedChannel.Name</h2>
                <p>@selectedChannel.Description</p>
            </div>

            <MessageList @ref="messageList"
                         Messages="displayMessages"
                         ReplyCountMap="replyCountMap"
                         IsLoadingMore="isLoadingMore"
                         HasMoreMessages="hasMoreMessages"
                         OnLoadMore="LoadMoreMessages"
                         OnOpenThread="OpenThread"
                         OnReact="HandleReaction" />

            <MessageInput OnSend="SendMessage" />
        }
        else
        {
            <div class="no-channel">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (isThreadOpen && threadRootMessage is not null)
    {
        <ThreadPanel RootMessage="threadRootMessage"
                     Replies="threadReplies"
                     OnClose="CloseThread"
                     OnSendReply="SendThreadReply" />
    }
</div>

@code {
    private MessageList? messageList;
    private List<Channel> channels = [];
    private Channel? selectedChannel;
    private int selectedChannelId;

    private List<Message> allMessages = [];
    private List<Message> displayMessages = [];
    private Dictionary<int, int> replyCountMap = new();
    private bool isLoadingMore;
    private bool hasMoreMessages = true;
    private const int PageSize = 50;

    private bool isThreadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task HandleChannelSelected(int channelId)
    {
        await SelectChannel(channelId);
    }

    private async Task SelectChannel(int channelId)
    {
        selectedChannelId = channelId;
        selectedChannel = channels.FirstOrDefault(c => c.Id == channelId);
        allMessages = [];
        hasMoreMessages = true;
        isThreadOpen = false;
        threadRootMessage = null;
        threadReplies = [];

        await LoadMessages();
        _ = ChatService.MarkChannelReadAsync(channelId);
    }

    private async Task LoadMessages()
    {
        var messages = await ChatService.GetMessagesAsync(selectedChannelId, allMessages.Count, PageSize);
        hasMoreMessages = messages.Count >= PageSize;
        allMessages.InsertRange(0, messages);
        UpdateDisplayMessages();
    }

    private async Task LoadMoreMessages()
    {
        if (isLoadingMore || !hasMoreMessages) return;
        isLoadingMore = true;
        StateHasChanged();

        await LoadMessages();
        isLoadingMore = false;
    }

    private void UpdateDisplayMessages()
    {
        displayMessages = allMessages
            .Where(m => m.ReplyToId is null)
            .OrderBy(m => m.SentAt)
            .ToList();

        replyCountMap = allMessages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(g => g.Key, g => g.Count());
    }

    private async Task SendMessage(string content)
    {
        var message = await ChatService.SendMessageAsync(selectedChannelId, content, null);
        allMessages.Add(message);
        UpdateDisplayMessages();

        if (messageList is not null)
        {
            await messageList.ScrollToBottomAsync();
        }
    }

    private async Task OpenThread(int messageId)
    {
        threadRootMessage = allMessages.FirstOrDefault(m => m.Id == messageId)
            ?? displayMessages.FirstOrDefault(m => m.Id == messageId);
        if (threadRootMessage is null) return;

        var thread = await ChatService.GetThreadAsync(messageId);
        threadReplies = thread
            .Where(m => m.Id != messageId)
            .OrderBy(m => m.SentAt)
            .ToList();
        isThreadOpen = true;

        // Update reply count from actual thread data
        replyCountMap[messageId] = threadReplies.Count;
    }

    private void CloseThread()
    {
        isThreadOpen = false;
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (threadRootMessage is null) return;
        var reply = await ChatService.SendMessageAsync(selectedChannelId, content, threadRootMessage.Id);
        threadReplies.Add(reply);
        replyCountMap[threadRootMessage.Id] = threadReplies.Count;
    }

    private async Task HandleReaction((int MessageId, string Emoji) reaction)
    {
        await ChatService.AddReactionAsync(reaction.MessageId, reaction.Emoji);

        // Optimistic local update
        var msgIndex = allMessages.FindIndex(m => m.Id == reaction.MessageId);
        if (msgIndex >= 0)
        {
            var msg = allMessages[msgIndex];
            var reactions = msg.Reactions.ToList();
            var existing = reactions.FindIndex(r => r.Emoji == reaction.Emoji);
            if (existing >= 0)
            {
                var r = reactions[existing];
                reactions[existing] = r with { Users = [.. r.Users, "You"] };
            }
            else
            {
                reactions.Add(new Reaction(reaction.Emoji, ["You"]));
            }
            allMessages[msgIndex] = msg with { Reactions = reactions };
            UpdateDisplayMessages();
        }
    }
}

.chat-container {
    display: grid;
    grid-template-columns: 250px 1fr;
    height: 100vh;
    overflow: hidden;
    background: #fff;
}

.chat-container.thread-open {
    grid-template-columns: 250px 1fr 350px;
}

.main-area {
    display: flex;
    flex-direction: column;
    height: 100vh;
    overflow: hidden;
    min-width: 0;
}

